var knightDialer = function(n) {
    const MOD = 1000000007n;
    const moves = [[4,6],[6,8],[7,9],[4,8],[0,3,9],[],[0,1,7],[2,6],[1,3],[2,4]];
    let dp = Array(10).fill(1n);
    for (let step = 1; step < n; step++) {
        const newDp = Array(10).fill(0n);
        for (let d = 0; d < 10; d++) {
            for (const nxt of moves[d]) {
                newDp[nxt] = (newDp[nxt] + dp[d]) % MOD;
            }
        }
        dp = newDp;
    }
    return Number(dp.reduce((a, b) => (a + b) % MOD, 0n));
};
